// ─────────────────────────────────────────────────────────────
// CONTEXT
// ─────────────────────────────────────────────────────────────
const CartContext = createContext(null);
export const useCart = () => {
  const ctx = useContext(CartContext);
  if (!ctx) throw new Error("useCart debe usarse dentro de CartProvider");
  return ctx;
};

// Deriva un uid estable desde el objeto user
const getUid = (user) => user?.id ?? user?.cliente_id ?? user?.email ?? null;

export const CartProvider = ({ children, user }) => {
  const uid = getUid(user);

  // Inicializar desde el localStorage del usuario actual
  const [items,    setItems]    = useState(() => loadLS(cartKey(uid)) || []);
  const [wishlist, setWishlist] = useState(() => loadLS(wishKey(uid)) || []);
  const [isOpen,   setIsOpen]   = useState(false);
  const [wishOpen, setWishOpen] = useState(false);
  const [pagoOpen, setPagoOpen] = useState(false);
  const [pedidoData, setPedidoData] = useState(null);

  // ── Cuando cambia el usuario, recargar datos del nuevo usuario ──
  useEffect(() => {
    setItems(loadLS(cartKey(uid)) || []);
    setWishlist(loadLS(wishKey(uid)) || []);
    setIsOpen(false);
    setWishOpen(false);
    setPagoOpen(false);
    setPedidoData(null);
  }, [uid]);

  // Persistir en la clave del usuario actual
  useEffect(() => { saveLS(cartKey(uid), items); },    [items, uid]);
  useEffect(() => { saveLS(wishKey(uid), wishlist); }, [wishlist, uid]);

  const cartCount = items.reduce((s,i)=>s+i.cantidad,0);
  const cartTotal = items.reduce((s,i)=>s+i.precioVenta*i.cantidad,0);
  const wishCount = wishlist.length;

  const addToCart = useCallback((prod) => {
    const { id,nombre,precioVenta,imagenPrincipal,imagenes,stockActual,cantidad=1 } = prod;
    setItems(prev => {
      const ex = prev.find(i=>i.id===id);
      if (ex) return prev.map(i=>i.id===id?{...i,cantidad:Math.min(i.cantidad+cantidad,stockActual)}:i);
      return [...prev,{id,nombre,precioVenta,imagenPrincipal,imagenes,stockActual,cantidad}];
    });
  },[]);

  const removeFromCart     = useCallback((id) => setItems(p=>p.filter(i=>i.id!==id)),[]);
  const updateQuantity     = useCallback((id,delta) => setItems(prev=>prev.map(item=>{
    if(item.id!==id) return item;
    const n=item.cantidad+delta;
    if(n<1||n>item.stockActual) return item;
    return {...item,cantidad:n};
  })),[]);
  const clearCart          = useCallback(()=>{ setItems([]); saveLS(cartKey(uid),[]); },[uid]);
  const toggleWishlist     = useCallback((prod)=>setWishlist(prev=>prev.find(i=>i.id===prod.id)?prev.filter(i=>i.id!==prod.id):[...prev,prod]),[]);
  const isInWishlist       = useCallback((id)=>wishlist.some(i=>i.id===id),[wishlist]);
  const removeFromWishlist = useCallback((id)=>setWishlist(p=>p.filter(i=>i.id!==id)),[]);
  const toggleCart         = useCallback(()=>setIsOpen(p=>!p),[]);
  const closeCart          = useCallback(()=>setIsOpen(false),[]);
  const openCart           = useCallback(()=>setIsOpen(true),[]);
  const openWishlist       = useCallback(()=>{ setWishOpen(true); setIsOpen(false); },[]);
  const closeWishlist      = useCallback(()=>setWishOpen(false),[]);
  const openPagoModal      = useCallback((data)=>{ setPedidoData(data); setPagoOpen(true); },[]);
  const closePagoModal     = useCallback(()=>{ setPagoOpen(false); setPedidoData(null); },[]);

  return (
    <CartContext.Provider value={{
      items,cartCount,cartTotal,isOpen,
      wishlist,wishCount,wishOpen,
      addToCart,removeFromCart,updateQuantity,clearCart,
      toggleWishlist,isInWishlist,removeFromWishlist,
      toggleCart,closeCart,openCart,openWishlist,closeWishlist,
      openPagoModal,closePagoModal,user,uid,
    }}>
      {children}
      {pagoOpen && pedidoData && (
        <PaymentModalInner
          isOpen={pagoOpen}
          onClose={closePagoModal}
          onPedidoCreado={(_id)=>{
            // Limpiar carrito y favoritos de los productos comprados
            const idsComprados = new Set(items.map(i => i.id));
            setWishlist(prev => {
              const nueva = prev.filter(w => !idsComprados.has(w.id));
              saveLS(wishKey(uid), nueva);
              return nueva;
            });
            clearCart();
            closePagoModal();
          }}
          items={pedidoData.items}
          total={pedidoData.total}
          metodoEntrega={pedidoData.metodoEntrega}
          direccion={pedidoData.direccion}
          user={user}
        />
      )}
    </CartContext.Provider>
  );
};

// ─────────────────────────────────────────────────────────────
// FORMULARIO DE DOMICILIO — Colombia GEO + celular + geoloc
// ─────────────────────────────────────────────────────────────
const DeliveryForm = ({ value, onChange, errors, uid }) => {
  const [geoLoading, setGeoLoading] = useState(false);
  const [geoError,   setGeoError]   = useState("");
  const [savedBanner, setSavedBanner] = useState(false);

  // Ciudades del departamento seleccionado
  const ciudades = useMemo(() =>
    value.departamento ? (COLOMBIA_GEO[value.departamento] || []) : [],
  [value.departamento]);

  // Cuando cambia el departamento, resetear ciudad si ya no es válida
  const handleDeptChange = (dept) => {
    const ciudadesNuevas = COLOMBIA_GEO[dept] || [];
    const ciudadOk = ciudadesNuevas.includes(value.ciudad) ? value.ciudad : "";
    onChange({ ...value, departamento: dept, ciudad: ciudadOk });
  };

  // Prefijo país automático según el número
  const formatCelular = (raw) => {
    const digits = raw.replace(/\D/g, "");
    if (!digits) return "";
    // Colombia: 10 dígitos empezando con 3
    if (digits.startsWith("3") && digits.length <= 10) return digits;
    // Si el usuario escribe código internacional (57...)
    if (digits.startsWith("57")) return digits.slice(0,12);
    return digits.slice(0,15);
  };

  const getCelularDisplay = (digits) => {
    if (!digits) return "";
    if (digits.startsWith("57")) return `+57 ${digits.slice(2)}`;
    if (digits.startsWith("3") && digits.length <= 10) return `+57 ${digits}`;
    return digits;
  };

  // Geolocalización
  const handleGeolocate = () => {
    if (!navigator.geolocation) { setGeoError("Tu navegador no soporta geolocalización."); return; }
    setGeoLoading(true); setGeoError("");
    navigator.geolocation.getCurrentPosition(
      async (pos) => {
        try {
          const { latitude, longitude } = pos.coords;
          // Nominatim (OpenStreetMap) — sin API key
          const res = await fetch(
            `https://nominatim.openstreetmap.org/reverse?lat=${latitude}&lon=${longitude}&format=json&addressdetails=1&accept-language=es`,
            { headers: { "User-Agent": "OpticaApp/1.0" } }
          );
          const data = await res.json();
          const addr = data.address || {};

          // Mapear estado de Nominatim a departamento de Colombia
          const estadoRaw = addr.state || addr.county || "";
          const deptMatch = DEPARTAMENTOS.find(d =>
            estadoRaw.toLowerCase().includes(d.toLowerCase()) ||
            d.toLowerCase().includes(estadoRaw.toLowerCase().replace("departamento de ","").replace("departamento del ",""))
          );

          const ciudadRaw = addr.city || addr.town || addr.village || addr.hamlet || addr.suburb || "";
          const ciudadesDisp = deptMatch ? (COLOMBIA_GEO[deptMatch] || []) : [];
          const ciudadMatch = ciudadesDisp.find(c =>
            ciudadRaw.toLowerCase().includes(c.toLowerCase()) ||
            c.toLowerCase().includes(ciudadRaw.toLowerCase())
          ) || "";

          const road   = addr.road || addr.pedestrian || addr.footway || "";
          const house  = addr.house_number || "";
          const barrio = addr.suburb || addr.neighbourhood || addr.quarter || "";

          onChange(prev => ({
            ...prev,
            departamento: deptMatch || prev.departamento,
            ciudad:       ciudadMatch || prev.ciudad,
            direccion:    prev.direccion || [road, house].filter(Boolean).join(" # "),
            barrio:       prev.barrio || barrio,
          }));
        } catch {
          setGeoError("No se pudo obtener la dirección. Completa manualmente.");
        } finally {
          setGeoLoading(false);
        }
      },
      (err) => {
        setGeoLoading(false);
        setGeoError(
          err.code === 1 ? "Permiso denegado. Activa la ubicación en tu navegador." :
          err.code === 2 ? "No se pudo obtener la ubicación." :
          "Tiempo de espera agotado."
        );
      },
      { timeout: 10000, maximumAge: 60000 }
    );
  };

  // Guardar dirección con banner de confirmación
  const handleSave = () => {
    saveLS(addrKey(uid), value);
    setSavedBanner(true);
    setTimeout(() => setSavedBanner(false), 2500);
  };

  return (
    <div className="sc-delivery-form">
      <div className="sc-delivery-header">
        <p className="sc-delivery-title">Dirección de entrega</p>
        {/* Botón geolocalización */}
        <button
          type="button"
          className={`sc-geo-btn${geoLoading?" sc-geo-btn--loading":""}`}
          onClick={handleGeolocate}
          disabled={geoLoading}
          title="Usar mi ubicación actual"
        >
          {geoLoading
            ? <span className="sc-geo-spin"/>
            : <svg viewBox="0 0 20 20" fill="none" stroke="currentColor" strokeWidth="1.5" width="14" height="14">
                <circle cx="10" cy="10" r="3"/><path d="M10 2v2M10 16v2M2 10h2M16 10h2"/>
                <path d="M10 7a3 3 0 100 6 3 3 0 000-6z" strokeOpacity="0"/>
              </svg>}
          {geoLoading ? "Obteniendo…" : "Usar mi ubicación"}
        </button>
      </div>

      {geoError && <div className="sc-geo-error">{geoError}</div>}

      {/* Departamento primero */}
      <div className="sc-field">
        <label>Departamento *</label>
        <select
          value={value.departamento}
          onChange={e => handleDeptChange(e.target.value)}
          className={errors.departamento?"sc-input--error":""}
        >
          <option value="">Seleccionar departamento…</option>
          {DEPARTAMENTOS.map(d => <option key={d} value={d}>{d}</option>)}
        </select>
        {errors.departamento && <span className="sc-field-error">{errors.departamento}</span>}
      </div>

      {/* Ciudad — solo habilitada si hay departamento */}
      <div className="sc-field">
        <label>Ciudad *</label>
        <select
          value={value.ciudad}
          onChange={e => onChange({...value, ciudad:e.target.value})}
          className={errors.ciudad?"sc-input--error":""}
          disabled={!value.departamento}
        >
          <option value="">{value.departamento ? "Seleccionar ciudad…" : "Primero selecciona departamento"}</option>
          {ciudades.map(c => <option key={c} value={c}>{c}</option>)}
        </select>
        {errors.ciudad && <span className="sc-field-error">{errors.ciudad}</span>}
      </div>

      {/* Dirección */}
      <div className="sc-field">
        <label>Dirección principal *</label>
        <input type="text" placeholder="Calle 10 # 43A-15" value={value.direccion}
          onChange={e=>onChange({...value,direccion:e.target.value})} className={errors.direccion?"sc-input--error":""} />
        {errors.direccion && <span className="sc-field-error">{errors.direccion}</span>}
      </div>

      {/* Apto + Barrio */}
      <div className="sc-field-row">
        <div className="sc-field">
          <label>Apto / Torre</label>
          <input type="text" placeholder="Apto 301" value={value.complemento}
            onChange={e=>onChange({...value,complemento:e.target.value})} />
        </div>
        <div className="sc-field">
          <label>Barrio *</label>
          <input type="text" placeholder="El Poblado" value={value.barrio}
            onChange={e=>onChange({...value,barrio:e.target.value})} className={errors.barrio?"sc-input--error":""} />
          {errors.barrio && <span className="sc-field-error">{errors.barrio}</span>}
        </div>
      </div>

      {/* Receptor */}
      <div className="sc-field">
        <label>Nombre del receptor *</label>
        <input type="text" placeholder="¿Quién recibe?" value={value.receptor}
          onChange={e=>onChange({...value,receptor:e.target.value})} className={errors.receptor?"sc-input--error":""} />
        {errors.receptor && <span className="sc-field-error">{errors.receptor}</span>}
      </div>

      {/* Celular con prefijo automático */}
      <div className="sc-field">
        <label>Celular *</label>
        <div className="sc-phone-wrap">
          <span className="sc-phone-flag">🇨🇴</span>
          <span className="sc-phone-prefix">+57</span>
          <input
            type="tel"
            placeholder="300 123 4567"
            value={value.celular.replace(/^(\+57|57)/,"")}
            onChange={e => {
              const digits = e.target.value.replace(/\D/g,"").slice(0,10);
              onChange({...value, celular: digits});
            }}
            className={errors.celular?"sc-input--error sc-phone-input":"sc-phone-input"}
          />
        </div>
        {errors.celular && <span className="sc-field-error">{errors.celular}</span>}
      </div>

      {/* Indicaciones */}
      <div className="sc-field">
        <label>Indicaciones</label>
        <textarea placeholder="Casa de rejas negras, llamar al llegar…" value={value.indicaciones}
          onChange={e=>onChange({...value,indicaciones:e.target.value})} rows={2} />
      </div>

      {/* Botón guardar dirección */}
      <button type="button" className="sc-save-addr-btn" onClick={handleSave}>
        {savedBanner
          ? <><svg viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="2" width="13" height="13"><polyline points="2 8 6 12 14 4"/></svg> ¡Dirección guardada!</>
          : <><svg viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="1.5" width="13" height="13"><path d="M2 2h9l3 3v9H2V2z"/><rect x="5" y="9" width="6" height="5" rx="0"/><rect x="6" y="2" width="4" height="3" rx="0"/></svg> Guardar esta dirección</>}
      </button>
    </div>
  );
};

