// SHOPPING CART DRAWER
// ─────────────────────────────────────────────────────────────
const ShoppingCart = ({ user }) => {
  const navigate = useNavigate();
  const { items,cartTotal,isOpen,removeFromCart,updateQuantity,clearCart,closeCart,openPagoModal,uid } = useCart();
  const [metodEntrega,    setMetodEntrega]   = useState("tienda");
  const [delivery,        setDelivery]       = useState(()=>loadLS(addrKey(uid))||emptyAddr);
  const [deliveryErrors,  setDeliveryErrors] = useState({});
  const [errorMsg,        setErrorMsg]       = useState("");

  // Recargar dirección guardada cuando cambia el usuario
  useEffect(() => {
    setDelivery(loadLS(addrKey(uid)) || emptyAddr);
  }, [uid]);

  const validateDelivery = () => {
    const e={};
    if(!delivery.departamento.trim()) e.departamento="Requerido";
    if(!delivery.ciudad.trim())       e.ciudad="Requerido";
    if(!delivery.direccion.trim())    e.direccion="Requerido";
    if(!delivery.barrio.trim())       e.barrio="Requerido";
    if(!delivery.receptor.trim())     e.receptor="Requerido";
    const cel = delivery.celular.replace(/\D/g,"");
    if(!cel||cel.length<10)           e.celular="10 dígitos requeridos";
    return e;
  };

  const handleCheckout = () => {
    if (!user) { closeCart(); navigate("/login"); return; }
    if (items.length===0) return;
    if (metodEntrega==="domicilio") {
      const errs = validateDelivery();
      if (Object.keys(errs).length>0) { setDeliveryErrors(errs); return; }
    }
    setDeliveryErrors({}); setErrorMsg("");
    const celDisplay = delivery.celular
      ? `+57 ${delivery.celular.replace(/^(\+57|57)/,"")}`
      : "";
    const dir = metodEntrega==="domicilio"
      ? [
          delivery.direccion,
          delivery.complemento && `, ${delivery.complemento}`,
          `, ${delivery.barrio}`,
          `, ${delivery.ciudad}`,
          `, ${delivery.departamento}`,
          `. Receptor: ${delivery.receptor}. Cel: ${celDisplay}`,
          delivery.indicaciones ? `. ${delivery.indicaciones}` : "",
        ].filter(Boolean).join("")
      : "";
    closeCart();
    openPagoModal({ items, total:cartTotal, metodoEntrega:metodEntrega, direccion:dir });
  };

  return (
    <>
      {isOpen && <div className="sc-backdrop" onClick={closeCart} aria-hidden="true" />}
      <div className={`sc-drawer${isOpen?" sc-drawer--open":""}`} role="dialog" aria-label="Carrito">
        <div className="sc-header">
          <h2 className="sc-title">
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5">
              <path d="M6 2L3 6v14a2 2 0 002 2h14a2 2 0 002-2V6l-3-4z"/>
              <line x1="3" y1="6" x2="21" y2="6"/>
              <path d="M16 10a4 4 0 01-8 0"/>
            </svg>
            Carrito
            {items.length>0 && <span className="sc-title-count">{items.length}</span>}
          </h2>
          <button className="sc-close" onClick={closeCart}>×</button>
        </div>

        <div className="sc-body">
          {items.length===0 && (
            <div className="sc-empty">
              <svg viewBox="0 0 64 64" fill="none" stroke="currentColor" strokeWidth="1.2">
                <path d="M8 2L2 8v40a4 4 0 004 4h44a4 4 0 004-4V8L48 2z"/>
                <line x1="2" y1="8" x2="58" y2="8"/>
                <path d="M40 24a8 8 0 01-16 0"/>
              </svg>
              <p>Tu carrito está vacío</p>
              <button className="sc-empty-btn" onClick={closeCart}>Explorar productos</button>
            </div>
          )}

          {items.length>0 && <>
            <ul className="sc-items">
              {items.map(item=>(
                <li key={item.id} className="sc-item">
                  <div className="sc-item-img">
                    {item.imagenPrincipal
                      ? <img src={item.imagenPrincipal} alt={item.nombre}/>
                      : <div className="sc-item-no-img"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5"><rect x="3" y="7" width="18" height="14" rx="2"/></svg></div>}
                  </div>
                  <div className="sc-item-data">
                    <p className="sc-item-name">{item.nombre}</p>
                    <p className="sc-item-price">{fmt(item.precioVenta)}</p>
                    <div className="sc-item-qty">
                      <button className="sc-qty-btn" onClick={()=>updateQuantity(item.id,-1)} disabled={item.cantidad<=1}>−</button>
                      <span className="sc-qty-val">{item.cantidad}</span>
                      <button className="sc-qty-btn" onClick={()=>updateQuantity(item.id,1)} disabled={item.cantidad>=item.stockActual}>+</button>
                    </div>
                  </div>
                  <div className="sc-item-right">
                    <span className="sc-item-subtotal">{fmt(item.precioVenta*item.cantidad)}</span>
                    <button className="sc-item-remove" onClick={()=>removeFromCart(item.id)}>
                      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5"><polyline points="3 6 5 6 21 6"/><path d="M19 6v14a2 2 0 01-2 2H7a2 2 0 01-2-2V6m3 0V4a1 1 0 011-1h4a1 1 0 011 1v2"/></svg>
                    </button>
                  </div>
                </li>
              ))}
            </ul>

            <div className="sc-options">
              <div className="sc-option-group">
                <label className="sc-option-label">Método de entrega</label>
                <div className="sc-radio-group">
                  <label className={`sc-radio${metodEntrega==="tienda"?" sc-radio--active":""}`}>
                    <input type="radio" name="entrega" value="tienda" checked={metodEntrega==="tienda"} onChange={()=>setMetodEntrega("tienda")}/>Retirar en tienda
                  </label>
                  <label className={`sc-radio${metodEntrega==="domicilio"?" sc-radio--active":""}`}>
                    <input type="radio" name="entrega" value="domicilio" checked={metodEntrega==="domicilio"} onChange={()=>setMetodEntrega("domicilio")}/>Domicilio
                  </label>
                </div>
              </div>

              <div className="sc-option-group">
                <label className="sc-option-label">Método de pago</label>
                <div className="sc-pago-info">
                  {metodEntrega==="tienda" ? (
                    <><svg viewBox="0 0 20 20" fill="none" stroke="currentColor" strokeWidth="1.5" width="14" height="14"><path d="M3 10h14M3 6h14M3 14h8"/></svg>Efectivo al retirar en tienda</>
                  ) : (
                    <><svg viewBox="0 0 20 20" fill="none" stroke="currentColor" strokeWidth="1.5" width="14" height="14"><rect x="2" y="5" width="16" height="11" rx="2"/><path d="M2 9h16"/></svg>Transferencia · Nequi · Bancolombia</>
                  )}
                </div>
              </div>

              {metodEntrega==="domicilio" && (
                <DeliveryForm
                  value={delivery}
                  onChange={setDelivery}
                  errors={deliveryErrors}
                  uid={uid}
                />
              )}
            </div>
            {errorMsg && <div className="sc-error-msg">{errorMsg}</div>}
          </>}
        </div>

        {items.length>0 && (
          <div className="sc-footer">
            <div className="sc-total-row">
              <span className="sc-total-label">Subtotal</span>
              <span className="sc-total-val">{fmt(cartTotal)}</span>
            </div>
            {!user && (
              <p className="sc-login-hint">
                <button className="sc-login-link" onClick={()=>{closeCart();navigate("/login");}}>Inicia sesión</button>{" "}para completar tu pedido.
              </p>
            )}
            <button className="sc-checkout-btn" onClick={handleCheckout}>
              {user
                ? metodEntrega === "tienda"
                  ? <>Reservar y pagar en tienda <svg viewBox="0 0 20 20" fill="none" stroke="currentColor" strokeWidth="2" width="14" height="14"><path d="M5 10h10M12 7l3 3-3 3"/></svg></>
                  : <>Pagar por transferencia <svg viewBox="0 0 20 20" fill="none" stroke="currentColor" strokeWidth="2" width="14" height="14"><path d="M5 10h10M12 7l3 3-3 3"/></svg></>
                : "Iniciar sesión para comprar"}
            </button>
            <button className="sc-clear-btn" onClick={clearCart}>Vaciar carrito</button>
          </div>
        )}
      </div>

      {/* Estilos extra para el formulario nuevo */}
      <style>{`
        .sc-delivery-header{display:flex;align-items:center;justify-content:space-between;gap:.5rem;margin-bottom:.5rem}
        .sc-delivery-title{font-size:.78rem;font-weight:700;color:rgba(255,255,255,.7);margin:0}
        .sc-geo-btn{display:flex;align-items:center;gap:.35rem;padding:.3rem .65rem;background:rgba(61,128,128,.18);border:1px solid rgba(61,128,128,.35);border-radius:.45rem;color:#6aaeae;font-size:.65rem;font-weight:600;cursor:pointer;transition:all .15s;font-family:inherit;white-space:nowrap}
        .sc-geo-btn:hover:not(:disabled){background:rgba(61,128,128,.3);border-color:#6aaeae}
        .sc-geo-btn:disabled{opacity:.55;cursor:default}
        .sc-geo-spin{width:11px;height:11px;border:2px solid rgba(106,174,174,.3);border-top-color:#6aaeae;border-radius:50%;animation:pmSpin .7s linear infinite;display:inline-block}
        .sc-geo-error{font-size:.65rem;color:#fca5a5;background:rgba(220,38,38,.1);border:1px solid rgba(220,38,38,.25);border-radius:.4rem;padding:.4rem .6rem;margin-bottom:.5rem}
        .sc-delivery-form select{width:100%;padding:.55rem .75rem;background:#0d2e2e;border:1px solid rgba(255,255,255,.15);border-radius:.5rem;color:#e2e8f0;font-size:.8rem;font-family:inherit;appearance:none;background-image:url("data:image/svg+xml,%3Csvg viewBox='0 0 10 6' fill='none' xmlns='http://www.w3.org/2000/svg'%3E%3Cpath d='M1 1l4 4 4-4' stroke='%236aaeae' stroke-width='1.5' stroke-linecap='round'/%3E%3C/svg%3E");background-repeat:no-repeat;background-position:right .75rem center;background-size:10px;cursor:pointer;transition:border-color .15s}
        .sc-delivery-form select:focus{outline:none;border-color:#6aaeae}
        .sc-delivery-form select:disabled{opacity:.45;cursor:not-allowed}
        .sc-phone-wrap{display:flex;align-items:center;background:#0d2e2e;border:1px solid rgba(255,255,255,.15);border-radius:.5rem;overflow:hidden;transition:border-color .15s}
        .sc-phone-wrap:focus-within{border-color:#6aaeae}
        .sc-phone-flag{padding:.55rem .4rem .55rem .65rem;font-size:.85rem;line-height:1;user-select:none}
        .sc-phone-prefix{font-size:.75rem;color:#6aaeae;font-weight:700;padding-right:.35rem;white-space:nowrap}
        .sc-phone-input{flex:1;padding:.55rem .75rem .55rem .2rem;background:transparent;border:none;color:#e2e8f0;font-size:.8rem;font-family:inherit;outline:none}
        .sc-save-addr-btn{display:flex;align-items:center;gap:.4rem;width:100%;padding:.5rem .75rem;background:rgba(61,128,128,.12);border:1px dashed rgba(61,128,128,.4);border-radius:.5rem;color:#6aaeae;font-size:.7rem;font-weight:600;cursor:pointer;transition:all .15s;font-family:inherit;justify-content:center;margin-top:.25rem}
        .sc-save-addr-btn:hover{background:rgba(61,128,128,.22);border-color:#6aaeae}
        @keyframes pmSpin{to{transform:rotate(360deg)}}
      `}</style>
    </>
  );
};

export default ShoppingCart;